params.command:
python -c "from pathlib import Path
root = Path('.')
skip = {'.git', '__pycache__', '.venv', 'node_modules'}
files = []
suffixes = {}
for p in root.rglob('*'):
    if any(part in skip for part in p.parts):
        continue
    if p.is_file():
        files.append(p)
        suffixes[p.suffix or '<none>'] = suffixes.get(p.suffix or '<none>', 0) + 1
main_files = [str(p.as_posix()) for p in files if p.name in {'app.py','run_desktop.py','README.md','requirements.txt'}]
tech = []
if any(p.suffix == '.py' for p in files): tech.append('Python/FastAPI')
if any(p.suffix in {'.js','.html','.css'} for p in files): tech.append('HTML/CSS/JavaScript')
print('file_count=' + str(len(files)))
print('technologies=' + ', '.join(tech))
print('main_files=' + ', '.join(main_files[:30]))
print('suffixes=' + str(dict(sorted(suffixes.items()))))
print('summary=LUXDEEP local FastAPI backend with LuxCode web frontend and agent/coder tooling.')
"

